mapper.select:
SELECT c.*, t.title as conv_title, t.unread_count, t.last_read_message_id FROM im_participant t INNER JOIN im_conversation c on t.conversation_id = c.id WHERE t.deleted = FALSE AND c.deleted = FALSE AND t.user_id = #{userId}
and t.conversation_id = #{query.conversationId}
and t.title like concat('%', #{query.title}, '%')
ORDER BY c.upd_time DESC

mapper.update:
UPDATE im_participant t
SET t.unread_count = IFNULL(t.unread_count, 0) + 1
WHERE t.conversation_id = #{conversationId}

    AND t.user_id != #{excludeUserId}

mapper.select:
SELECT t.*, u.name, u.img
FROM im_participant t
LEFT JOIN base_user u ON t.user_id = u.id
WHERE t.conversation_id = #{query.conversationId}
ORDER BY t.id ASC
LIMIT #{query.limit}
